import{_ as i,o as a,c as l,a4 as d}from"./chunks/framework.B4F_pDg-.js";const E=JSON.parse('{"title":"IDE介绍","description":"","frontmatter":{},"headers":[],"relativePath":"docs/ide/index.md","filePath":"docs/ide/index.md"}'),t={name:"docs/ide/index.md"};function o(r,e,n,s,h,c){return a(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="ide介绍" tabindex="-1">IDE介绍 <a class="header-anchor" href="#ide介绍" aria-label="Permalink to “IDE介绍”">​</a></h1><p><em>最后编辑于2026/06/07 by:nood</em></p><p>IDE(Integrated Development Environment) 中文:集成开发环境 我们一般都叫IDE 是一种把程序员开发所需的各类工具整合到一起的的应用</p><p>核心组件:</p><ul><li>代码编辑器: 提供语法高亮 自动补全等功能</li><li>编译器/解释器: 将源代码转成计算机可以执行的指令</li></ul><h2 id="常见ide" tabindex="-1">常见IDE <a class="header-anchor" href="#常见ide" aria-label="Permalink to “常见IDE”">​</a></h2><ul><li>Visual Studio Code: 简称vscode 微软开发的代码编辑器 非常轻量的软件 写什么语言都可以 丰富的插件 如果你不止写一种编程语言 非常建议你用 但是配置比较麻烦 不过这些都不是问题! 面缶酱会教你的喵~<br><em>应该有人知道Visual Studio Code本质上不是IDE而是代码编辑器 不过因为Visual Studio Code确实好用 所有上面还是列出来了 不过还是要记住Visual Studio Code不是IDE 而是代码编辑器</em></li><li>IDLE: Python自带的IDE 全英文 如果你的电脑配置没那么好 可以试试这个</li><li>PyCharm: JetBrains开发的IDE 写Python最好用的IDE</li><li>Dev C++: 一个非常基础的专门为C/C++设计的IDE 如果你的电脑配置没那么好 可以试试这个</li><li>Visual Studio: 简称vs 微软开发的一个IDE 写C系列语言 .NET首选</li><li>IntelliJ IDEA: JetBrains开发的IDE 写Java Kotlin首选IDE</li></ul><h2 id="安装ide" tabindex="-1">安装IDE <a class="header-anchor" href="#安装ide" aria-label="Permalink to “安装IDE”">​</a></h2><ul><li>安装<a href="./docs/ide/vscode.html">Visual Studio Code</a></li><li>安装IDLE(仅windows)请见安装<a href="/docs/py/install.html#安装">Python3</a></li><li>安装<a href="./docs/ide/pycharm.html">PyCharm</a></li></ul>',9)])])}const I=i(t,[["render",o]]);export{E as __pageData,I as default};
